                "photo_list": [
                    {
                        "photo_url": "http://mmbiz.qpic.cn/mmbiz_png/tW66AWvE2K6icjle1q6nbfKr0HMibzxKqOUfG1hARktHV84ZZojt9cXZ0UicDevZQUicckPw68lfo2Le3RjpEo6oLg/0?wx_fmt=png"
                    }
                ],
                "open_time": "11:00-12:00",
                "poi_id": "472671857",
                "status": 3,
                "district": "阿城区",
                "qualification_list": [],
                "qualification_num": "91750100ME2XCR6A70",
                "qualification_name": "龙涤小区熟食店"
            }
        }
    ],
    "total_count": 2
}
 # 6. 错误码 以下是本接口的错误码列表，其他错误码可参考 通用错误码；调用接口遇到报错，可使用官方提供的 API 诊断工具 辅助定位和分析问题。 错误码错误描述解决方案 40001invalid credential  access_token isinvalid or not latest获取 access_token 时 AppSecret 错误，或者 access_token 无效。请开发者认真比对 AppSecret 的正确性，或查看是否正在为恰当的公众号调用接口  # 7. 适用范围 本接口在不同账号类型下的可调用情况： 公众号服务号 ✔ ✔ ✔：该账号可调用此接口其他未明确声明的账号类型，如无特殊说明，均不可调用此接口；

# 获取门店详情  调试诊断 接口应在服务器端调用，不可在前端（小程序、网页、APP等）直接调用，具体可参考接口调用指南 接口英文名：newgetpoi 本接口用于获取门店详情  # 1. 调用方式 # HTTPS 调用 POST https://api.weixin.qq.com/wxa/get_store_info?access_token=ACCESS_TOKEN
# 云调用 本接口不支持云调用 # 第三方调用 本接口支持第三方平台代商家调用。 该接口所属的权限集 id 为：8-10、13 服务商获得其中之一权限集授权后，可通过使用 authorizer_access_token 代商家进行调用，具体可查看 第三方调用 说明文档。  # 2. 请求参数 # 查询参数 Query String parameters 参数名类型必填说明 access_tokenstring是接口调用凭证，可使用 access_token、authorizer_access_token # 请求体 Request Payload 参数名类型必填说明 poi_idstring是为门店小程序添加门店，审核成功后返回的门店id  # 3. 返回参数 # 返回体 Response Payload 参数名类型说明 errcodenumber错误码 errmsgstring错误描述  # 4. 注意事项 本接口无特殊注意事项  # 5. 代码示例 请求示例 {
  "poi_id":"472671857"
}
返回示例 {
    "errcode": 0,
    "errmsg": "ok",
    "business": {
        "base_info": {
            "business_name": "龙涤小区熟食店",
            "address": "舍利街道中都大道龙涤小区阿升电脑旁",
            "telephone": "12345678",
            "city": "哈尔滨市",
            "province": "黑龙江省",
            "longitude": 126.94355011,
            "latitude": 45.556098938,
            "photo_list": [
                {
                    "photo_url": "http://mmbiz.qpic.cn/mmbiz_png/tW66AWvE2K6icjle1q6nbfKr0HMibzxKqOUfG1hARktHV84ZZojt9cXZ0UicDevZQUicckPw68lfo2Le3RjpEo6oLg/0?wx_fmt=png"
                }
            ],
            "open_time": "11:00-12:00",
            "poi_id": "472671857",
            "status": 2,
            "district": "value",
            "qualification_num": "91750100ME2XCR6A70",
            "qualification_name": "龙涤小区熟食店"
        }
    }
}
 # 6. 错误码 以下是本接口的错误码列表，其他错误码可参考 通用错误码；调用接口遇到报错，可使用官方提供的 API 诊断工具 辅助定位和分析问题。 错误码错误描述解决方案 40001invalid credential  access_token isinvalid or not latest获取 access_token 时 AppSecret 错误，或者 access_token 无效。请开发者认真比对 AppSecret 的正确性，或查看是否正在为恰当的公众号调用接口  # 7. 适用范围 本接口在不同账号类型下的可调用情况： 公众号服务号 ✔ ✔ ✔：该账号可调用此接口其他未明确声明的账号类型，如无特殊说明，均不可调用此接口；

# 新增门店  调试诊断 接口应在服务器端调用，不可在前端（小程序、网页、APP等）直接调用，具体可参考接口调用指南 接口英文名：addentityshop 本接口用于新增门店  # 1. 调用方式 # HTTPS 调用 POST https://api.weixin.qq.com/wxa/add_store?access_token=ACCESS_TOKEN
# 云调用 本接口不支持云调用 # 第三方调用 本接口支持第三方平台代商家调用。 该接口所属的权限集 id 为：8-10、13 服务商获得其中之一权限集授权后，可通过使用 authorizer_access_token 代商家进行调用，具体可查看 第三方调用 说明文档。  # 2. 请求参数 # 查询参数 Query String parameters 参数名类型必填说明 access_tokenstring是接口调用凭证，可使用 access_token、authorizer_access_token # 请求体 Request Payload 参数名类型必填说明 map_poi_idstring是从腾讯地图换取的位置点id， 即search_map_poi接口返回的sosomap_poi_uid字段 pic_liststring是门店图片，可传多张图片，字段是一个 json 字符串 contract_phonestring是联系电话 hourstring是营业时间，格式11:11-12:12 credentialstring是经营资质证件号 company_namestring否主体名字，如果复用公众号主体，则company_name为空，如果不复用公众号主体，则company_name为具体的主体名字 card_idstring是卡券id，如果不需要添加卡券，该参数可为空 目前仅开放支持会员卡、买单和刷卡支付券，不支持自定义code，需要先去公众平台卡券后台创建cardid qualification_listarray否相关证明材料   临时素材mediaid 不复用公众号主体时，才需要填 支持0~5个mediaid，例如mediaid1 或 mediaid2 poi_idstring否如果是从门店管理迁移门店到门店小程序，则需要填该字段  # 3. 返回参数 # 返回体 Response Payload 参数名类型说明 errcodenumber错误码 errmsgstring错误描述 dataobject新增信息  # Res.data Object Payload 新增信息 参数名类型说明 audit_idnumber审核id  # 4. 注意事项 本接口无特殊注意事项  # 5. 代码示例 请求示例 {
  "poi_id": "",
  "map_poi_id": "2880741500279549033",
  "pic_list":"{\"list\":[\"http://mmbiz.qpic.cn/mmbiz_jpg/tW66AWvE2K4EJxIYOVpiaGOkfg0iayibiaP2xHOChvbmKQD5uh8ymibbEKlTTPmjTdQ8ia43sULLeG1pT2psOfPic4kTw/0?wx_fmt=jpeg\"]}",
  "contract_phone": "1111222222",
  "credential": "22883878-0",
  "qualification_list": "RTZgKZ386yFn5kQSWLTxe4bqxwgzGBjs3OE02cg9CVQk1wRVE3c8fjUFX7jvpi-P"
}
返回示例 {
  "errcode" : 0,
  "errmsg" : "ok",
  "data" : {
    "audit_id":111
  }
}
 # 6. 错误码 以下是本接口的错误码列表，其他错误码可参考 通用错误码；调用接口遇到报错，可使用官方提供的 API 诊断工具 辅助定位和分析问题。 错误码错误描述解决方案 40001invalid credential  access_token isinvalid or not latest获取 access_token 时 AppSecret 错误，或者 access_token 无效。请开发者认真比对 AppSecret 的正确性，或查看是否正在为恰当的公众号调用接口 85038store has added 请勿添加重复门店 85039store has added by others 此门店状态不能被获取信息 85040store has added by yourseld 此门店已被绑定，无需重复绑定 85041credential has used该经营资质已添加，请勿重复添加 85042nearby reach limit 附近地点添加数量达到上线，无法继续添加。 85054poi_id is null由于门店小程序还没升级成功，需要添写poi_id进行门店迁移 85055map_poi_id is invalidmap_poi_id 无效 85056mediaid is invalid 临时mediaid无效  # 7. 适用范围 本接口在不同账号类型下的可调用情况： 公众号服务号 ✔ ✔ ✔：该账号可调用此接口其他未明确声明的账号类型，如无特殊说明，均不可调用此接口；

