      "thumb_media_id": "THUMB_MEDIA_ID",
      "thumb_url": "THUMB_URL",
      "show_cover_pic": 1,
      "need_open_comment": 0,
      "only_fans_can_comment": 0,
      "url": "URL",
      "is_deleted": false
    }
  ]
}
